41	const itemEntries = (items: any[]): ItemEntry[] => {
42	  const entries: ItemEntry[] = [];
43	  const componentCounts: Record<string, number> = {};
44	  for (const item of items) {
45	    if (COMPONENT_TYPES.has(item.type)) {
46	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
47	    } else {
48	      const base = BASE_PREMIUM[item.type];
49	      let surchargePct = FIRST_INSURANCE_SURCHARGE;
50	      if (item.cursed) surchargePct += CURSE_SURCHARGE;
51	      if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
52	        surchargePct += HIGH_ENCHANTMENT_SURCHARGE;
53	      }
54	      entries.push({ base, surchargePct });
55	    }
56	  }
57	  for (const [type, count] of Object.entries(componentCounts)) {
58	    entries.push({
59	      base: componentBasePremium(count, BASE_PREMIUM[type]),
60	      surchargePct: FIRST_INSURANCE_SURCHARGE,
61	    });
62	  }
63	  return entries;
